    def test_string_with_no_brackets_is_balanced(self):
        assert is_balanced_parens("hello world") is True

    def test_single_pair_parentheses(self):
        assert is_balanced_parens("()") is True

    def test_single_pair_brackets(self):
        assert is_balanced_parens("[]") is True

    def test_single_pair_braces(self):
        assert is_balanced_parens("{}") is True

    def test_multiple_balanced_pairs(self):
        assert is_balanced_parens("()[]{}") is True

    def test_nested_balanced_pairs(self):
        assert is_balanced_parens("([{}])") is True

    def test_balanced_pairs_with_other_characters(self):
        assert is_balanced_parens("a(b[c]{d}e)f") is True

    def test_unclosed_open_paren(self):
